SELECT ur.user_two_id AS friend_id, u.nickname, ur.remark_one AS remark, u.role AS role, u.avatar_url AS avatar_url FROM user_relationships ur JOIN users u ON ur.user_two_id = u.id WHERE ur.user_one_id = #{userId} AND ur.status = 1
UNION ALL
SELECT ur.user_one_id AS friend_id, u.nickname, ur.remark_two AS remark, u.role AS role, u.avatar_url AS avatar_url FROM user_relationships ur JOIN users u ON ur.user_one_id = u.id WHERE ur.user_two_id = #{userId} AND ur.status = 1;

SELECT u.id AS friend_id, u.nickname, u.avatar_url AS avatar_url, u.role, CASE WHEN ur.user_one_id = #{currentUserId} THEN ur.remark_one WHEN ur.user_two_id = #{currentUserId} THEN ur.remark_two END AS remark FROM users u LEFT JOIN user_relationships ur ON (ur.user_one_id = #{currentUserId} AND ur.user_two_id = u.id) OR (ur.user_one_id = u.id AND ur.user_two_id = #{currentUserId}) WHERE u.id IN
#{friendId}
AND ur.status = 1
